let _oc = 0;
const uid = () => "o" + (++_oc) + "_" + Date.now();
const defaultOffer = (n) => ({ id: uid(), name: "Offer " + n, segments: [], activity: "Charging session", wpre: false, w: "", wa: "Campaign start date", dist: "spread", wsx: "", wsxType: "fixed", reward: "Cashback", tiers: [{ s: "1", pct: "7" }, { s: "2", pct: "10" }, { s: "3", pct: "12" }], dpct: "", xpwpct: "", p: "", un: "10", ux: "", nx: "", cy: "100", dy: "", wm: "", sn: "", sx: "", t: "30", te: "", ce: "30", ctMode: "off", wtMode: "none", wtSlabs: [{ min: "100", max: "499", pct: "5" }, { min: "500", max: "999", pct: "8" }, { min: "1000", max: "", pct: "12" }], rc: null, rcFileName: "", rcCount: 0, rcLogic: "intersection" });
